function CompanyLogo({
  logo,
  alt,
  height = 20,
}: {
  logo?: string;
  alt: string;
  height?: number;
}) {
  if (!logo) return null;
  return (
    <img
      src={logo}
      alt={alt}
      style={{
        height: `${height}px`,
        width: "auto",
        maxWidth: "80px",
        objectFit: "contain",
        borderRadius: "3px",
      }}
      onError={(e) =>
        ((e.currentTarget as HTMLImageElement).style.display = "none")
      }
    />
  );
}

